import React, { useState } from 'react';

const App = () => {
  const [priceFilter, setPriceFilter] = useState('All');
  const [brandFilter, setBrandFilter] = useState('All');
  const [categoryFilter, setCategoryFilter] = useState('All');
  const [products, setProducts] = useState([
    { id: 1, name: 'Product 1', price: 9.99, brand: 'Brand A', category: 'Category A' },
    { id: 2, name: 'Product 2', price: 14.99, brand: 'Brand B', category: 'Category B' },
    { id: 3, name: 'Product 3', price: 7.99, brand: 'Brand C', category: 'Category C' }
  ]);

  const handlePriceFilterChange = (event) => {
    setPriceFilter(event.target.value);
  };

  const handleBrandFilterChange = (event) => {
    setBrandFilter(event.target.value);
  };

  const handleCategoryFilterChange = (event) => {
    setCategoryFilter(event.target.value);
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="flex flex-col items-center">
        <div className="bg-[#B7D7CD] p-4 w-80">
          <h2 className="text-lg font-bold mb-2">Product Grid</h2>
          <div className="grid grid-cols-3 gap-4">
            {products.map((product) => (
              <div key={product.id} className="bg-[#C06C88] p-4 rounded shadow-md">
                <h3 className="text-lg font-bold mb-2">{product.name}</h3>
                <p className="text-sm font-medium mb-2">${product.price}</p>
                <p className="text-sm font-medium">{product.brand}</p>
              </div>
            ))}
          </div>
        </div>
        <div className="bg-[#090a0f] p-4 w-80 mt-4">
          <h2 className="text-lg font-bold mb-2">Filters</h2>
          <div className="flex flex-col items-center">
            <div className="bg-[#B7D7CD] p-4 w-80 mt-4">
              <label className="text-lg font-bold mb-2">Price:</label>
              <select className="bg-[#C06C88] p-2 rounded shadow-md" value={priceFilter} onChange={handlePriceFilterChange}>
                <option value="All">All</option>
                <option value="Under $10">Under $10</option>
                <option value="$10-$20">$10-$20</option>
                <option value="Over $20">Over $20</option>
              </select>
            </div>
            <div className="bg-[#B7D7CD] p-4 w-80 mt-4">
              <label className="text-lg font-bold mb-2">Brand:</label>
              <select className="bg-[#C06C88] p-2 rounded shadow-md" value={brandFilter} onChange={handleBrandFilterChange}>
                <option value="All">All</option>
                <option value="Brand A">Brand A</option>
                <option value="Brand B">Brand B</option>
                <option value="Brand C">Brand C</option>
              </select>
            </div>
            <div className="bg-[#B7D7CD] p-4 w-80 mt-4">
              <label className="text-lg font-bold mb-2">Category:</label>
              <select className="bg-[#C06C88] p-2 rounded shadow-md" value={categoryFilter} onChange={handleCategoryFilterChange}>
                <option value="All">All</option>
                <option value="Category A">Category A</option>
                <option value="Category B">Category B</option>
                <option value="Category C">Category C</option>
              </select>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;
